            await comp.Find("#reset-string").ClickAsync();

            select.Value.Should().BeNullOrEmpty();
            select.GetState(x => x.SelectedValues).Should().BeEmpty();
            select.ValidationErrors.Should().BeEmpty();

            //test clearing object values
