        [Test]
        public async Task Select_OpenMenu_ScrollsToSelectedItemAfterItemsRender()
        {
            var scrollManager = new Mock<IScrollManager>();
            Context.Services.AddSingleton(scrollManager.Object);

            var comp = Context.RenderComponent<MudSelect<string>>(parameters => parameters
                .Add(x => x.Value, "4")
                .AddChildContent(builder =>
                {
                    AddSelectItem(builder, 0, "1");
                    AddSelectItem(builder, 3, "2");
                    AddSelectItem(builder, 6, "3");
                    AddSelectItem(builder, 9, "4");
                }));

            await comp.InvokeAsync(() => comp.Instance.OpenMenu());
            await comp.WaitForAssertionAsync(() =>
                scrollManager.Verify(x => x.ScrollToListItemAsync(It.IsAny<string>()), Times.Once));
        }

        private static void AddSelectItem(RenderTreeBuilder builder, int sequence, string value)
        {
            builder.OpenComponent<MudSelectItem<string>>(sequence);
            builder.AddAttribute(sequence + 1, nameof(MudSelectItem<string>.Value), value);
            builder.AddAttribute(sequence + 2, nameof(MudSelectItem<string>.ChildContent), (RenderFragment)(itemBuilder => itemBuilder.AddContent(0, value)));
            builder.CloseComponent();
        }

